/* Sanal POS Ödeme Sistemi Stilleri */

.sanal-pos-payment-form {
    max-width: 500px;

    .input-group-text {
        background-color: #fff;
        i {
            font-size: 1.5rem;
            color: #6c757d;
        }
    }

    .list-group-item {
        cursor: pointer;
        transition: all 0.2s ease;

        &:hover {
            background-color: #f8f9fa;
        }

        &.active {
            background-color: #0d6efd;
            border-color: #0d6efd;
        }
    }
}

.sanal-pos-installment-widget {
    .card-header {
        background-color: #f8f9fa;

        h5 {
            font-size: 1rem;
            color: #495057;
        }
    }

    .btn-sm {
        font-size: 0.8rem;
        padding: 0.25rem 0.75rem;
    }

    table {
        font-size: 0.9rem;

        th {
            background-color: #f8f9fa;
            font-weight: 600;
        }
    }
}

.sanal-pos-installment-selector {
    .installment-option {
        padding: 0.5rem 0.75rem;
        border: 1px solid #dee2e6;
        border-radius: 0.375rem;
        margin-bottom: 0.25rem;
        cursor: pointer;
        transition: all 0.15s ease;

        &:hover {
            background-color: #f8f9fa;
            border-color: #adb5bd;
        }

        &.selected {
            background-color: #e7f1ff;
            border-color: #0d6efd;
        }

        .form-check-label {
            cursor: pointer;
        }
    }
}

/* 3D Secure Yönlendirme */
.sanal-pos-3d-redirect {
    text-align: center;
    padding: 2rem;

    .spinner-border {
        width: 3rem;
        height: 3rem;
    }

    p {
        font-size: 1.1rem;
        margin-top: 1rem;
        color: #495057;
    }
}
